[SysClientCacheDataMethodAttribute(true)]
public static display AmountNoDecimals showTradeLimit(SalesAgreementHeader _this)
{
    return CustTable::find(_this.CustAccount).ETGTradeLimitSalesReal;
}

public void modifiedField(FieldId _fieldId)
{

    next modifiedField(_fieldId);
    switch (_fieldId)
    {
        case fieldNum(SalesAgreementHeader, AgreementState):
            AgreementLineQuantityCommitment aLine;
            LineAmount                      totalAgreementAmt;
            CustTable                       custTable;
            ETGACFParameters                _eTGACFParameters = ETGACFParameters::find();

            if(_eTGACFParameters.EnableTradeLimit == NoYes::Yes)
            {
                while select aLine where aLine.Agreement == this.RecId
                {
                    totalAgreementAmt += aLine.lineAmount();
                }

                if(totalAgreementAmt != 0)
                {
                    custTable = CustTable::find(this.CustAccount, true);

                    if(custTable.ETGApplicableTradeLimit == NoYes::Yes)
                    {
                        if(totalAgreementAmt > custTable.ETGRemainingTradeLimitSalesReal)
                        {
                            throw Error(strFmt("@ETG:ErrorTradeLimit1", totalAgreementAmt, custTable.ETGRemainingTradeLimitSalesReal));
                        }

                        ttsbegin;
                        custTable.ETGRemainingTradeLimitSalesReal = custTable.ETGRemainingTradeLimitSalesReal - totalAgreementAmt;
                        custTable.doUpdate();
                        ttscommit;
                    }
                }
            }
    }
}
